class Solution(object):
    def countSubarrays(self, nums, k):
        max_val = max(nums)
        n = len(nums)
        ans = 0
        left = 0
        count = 0  # count of max_val in window
        for right in range(n):
            if nums[right] == max_val:
                count += 1
            while count >= k:
                ans += n - right  # subarrays starting at left, ending at right..n-1
                if nums[left] == max_val:
                    count -= 1
                left += 1
        return ans
